const isJest = typeof process.env.JEST_WORKER_ID === "string";
/** @type {Console["log"]} */
const log = (() => isJest ? () => { } : console.log)();
const timeStart = (() => isJest ? () => { } : console.time.bind(console))();
const timeEnd = (() => isJest ? () => { } : console.timeEnd.bind(console))();

// - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
//                            Task functions.
// - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
/**
 * @param {Parameters<typeof rimraf.sync>[0]} globPattern 
 * @param {() => unknown} cb 
 */
const cleanUpResults = (globPattern, cb) => {
  rimraf.sync(globPattern);
  cb();
};
/**
 * @type {TBivariant< Required<Parameters<IRemoveCStyleComments["setListener"]>>[0] >}
 */
const preserveJSDoc = ({ event, fragment }) => {
  if (event === /*EScannerEvent.MultiLineComment*/1) {
    return /^\/\*(\*|!)\s|^\/\*(?!-).+\*\/$/.test(fragment);
  }
  return false;
};
/** @type {(code: string) => string} */
const toRegexLieteral = (code) => code.replace(/\\\\/g, "\\").replace(/(?<=^\s+)"(.+?\/(?:\w+)?)"(?=,?)/gm, "$1");


/**
 * Generates source code from the given content.
 * @param {TDetectedReContext} ctx - The content to be included in the source code.
 * @param {string} name - The name of the variable to hold the content.
 * @returns {string} - The generated source code.
 */
const generateSource = (ctx, name = "uniqLiterals") => {
  // TDetectedReContext detectedReLiterals
  const { uniqReLiterals, detectedReLiterals } = ctx;
  return `//
// Auto generated by "scripts/grmc-test-task.js"
//

// ${name}: ${uniqReLiterals.length} entries
const ${name} = ${toRegexLieteral(
    utils.formatedStringify(uniqReLiterals.sort((a, b) => a.length - b.length))
  )
    // JSON.stringify(uniqReLiterals.sort((a, b) => a.length - b.length))
    //     .replace(/\\\\/g, "\\").replace(/(?<=^\s+)"(.+?\/(?:\w+)?)"(?=,?)/gm, "$1")
    };

// detectedReLiterals: ${detectedReLiterals.length} entries
const detectedReLiterals = ${toRegexLieteral(
      utils.formatedStringify(detectedReLiterals)
    )
    };
module.exports = {
  ${name},
  detectedReLiterals
};
`;
};
