/**
 * Formats the statistics of JSDoc tags.
 * @param {TPriorityEntry[]} content - The content to be formatted.
 * @returns {string} - The formatted statistics.
 */
const formatStatictics = (content) => {
  return `const jsDocTagStatistics = [
  ${content.map(entry => `["${entry[0]}", ${entry[1]}]`)
      .reduce((acc, value) => {
        return acc + value + ",\n  ";
        // return acc + value + (idx && !(idx % 5) ? ",\n  ": ", ");
      }, "")}
];
module.exports = {
  jsDocTagStatistics
};
`;
};
/**
 * @param {string} summary 
 */
const detectNodeVersion = (summary) => {
  const m = /Node.JS: (\d+)\./.exec(summary);
  if (m) return +m[1];
  return 0;
};
/**
 * Finalizes the task by writing the results to files.
 * @param {TDetectedReContext} context - The detected regex context.
 * @param {TPriorityEntry[]} tagPriorityEntries - The JSDoc tag priority entries.
 * @param {NsGulpRmc.TTimeSpanEntries} timeSpans - The time spans.
 * @param {number} pending - The number of pending tasks.
 * @param {() => void} cb - The callback function to be called after finalization.
 * @param {{ LOG_ROOT: string; platfromSummary?: string }} payload
 */
const final = (context, tagPriorityEntries, timeSpans, pending, cb, payload) => {
  /**
   * @type {Parameters<typeof utils.writeText>[2]}
   */
  const writeCallback = () => {
    --pending === 0 && cb();
  };
  const { LOG_ROOT, platfromSummary = "" } = payload;
  const nv = detectNodeVersion(platfromSummary);
  const logDest = `${LOG_ROOT}/${utils.dateStringForFile()}_node${nv}`;

  context.uniqReLiterals.length && utils.writeText(
    generateSource(context),
    // generateSource(context.uniqReLiterals, "reLiterals"),
    `${logDest}/grmc-detected-reLiterals.js`,
    writeCallback
  );
  tagPriorityEntries.length && utils.writeText(
    formatStatictics(tagPriorityEntries),
    `${logDest}/grmc-detected-jsdocTags.js`,
    writeCallback
  );
  timeSpans.length && utils.writeText(
    utils.formatedStringify(timeSpans),
    `${logDest}/grmc-time-spans_node${nv}.json`,
    // "./tmp/grmc-time-spans.json",
    writeCallback
  );
};

/**
 * @param {Map<TJSDocTag, number>} tagStats
 * @returns {TPriorityEntry[]}
 */
const getTagStatistics = (tagStats) => {
  /**
   * @type {MapIterator<[`@${string}`, number]>}
   */
  const entries = tagStats.entries();
  /** @type {TPriorityEntry[]} */
  const ret = [];
  do {
    const { value, done } = entries.next();
    if (done) break;
    ret.push(value);
  } while (1);

  return ret.sort((a, b) => {
    //* cct
    const diff = b[1] - a[1];
    if (!diff) return b[0].localeCompare(a[0]);
    return diff;
    /*/
    const diff = a[1] - b[1];
    return diff === 0 ? a[0].localeCompare(b[0]) : diff;
    //*/
  });
};



/**
 * @param {TGrmcTaskArgs} settings
 * @param {Map<TJSDocTag, number>} tagStats
 * @returns {[IScanEventCallback, () => number]}
 */
const emitListener = (settings, tagStats) => {

  const collectTag = settings.collectJSDocTag;
  const iswalk = settings.isWalk ?? false;
  const reJsDocTag = /(?<=[\s\*{])@\w+(?=\s)/g;
  let inlineSourceMap = 0;
  /**
   * @param {object} context
   * @param {TScannerEventContext["event"]} context.event
   * @param {TScannerEventContext["fragment"]} context.fragment
   */
  const linstener = ({ event, fragment }) => {
    if (event === /*ScannerEvent.MultiLineComment*/1) {
      if (collectTag && /^\/\*\*[^*]/.test(fragment)) {
        const re = reJsDocTag; // regex for correct detection
        /** @type {RegExpExecArray | null} */
        let m;
        while (m = re.exec(fragment)) {
          const tag = /** @type {TJSDocTag} */(m[0]);
          let count = tagStats.get(tag) ?? 0;
          tagStats.set(tag, count + 1);
        }
      }
    } else if (event === /*ScannerEvent.SingleLineComment*/0) {
      // OLD regex: /^\/\/# sourceMappingURL=data:application/ => detected inline source map: 131
      // New regex: /^\/\/[@#]\s*sourceMappingURL=/            => detected inline source map: 1048
      // if (/^\/\/# sourceMappingURL=data:application/.test(fragment)) {
      if (/^\/\/[@#]\s*sourceMappingURL=/.test(fragment)) {
        // !silent && log(`\ninline source map detected=[${fragment.substring(0, 48)}...]`);
        inlineSourceMap++;
      }
    }
    return iswalk;
  };
  const getInlineSourceMapCount = () => inlineSourceMap;

  return [
    linstener, getInlineSourceMapCount
  ];
};


module.exports = {
  isJest,
  log, timeStart, timeEnd,
  final,
  emitListener,
  preserveJSDoc,
  cleanUpResults,
  getTagStatistics,
};
